send-request.set-url:
@{
          var upn = (string)context.Variables["citizenUpn"];
          var dvUrl = "{{d365-dataverse-url}}".TrimEnd('/');
          var filter = "contains(description,'citizenUpn: " + upn + "')";
          var select = "activityid,subject,description,createdon,modifiedon,statecode,statuscode,prioritycode";
          var orderby = "createdon desc";
          return dvUrl + "/api/data/v9.2/tasks?$select=" + System.Net.WebUtility.UrlEncode(select)
                       + "&$filter=" + System.Net.WebUtility.UrlEncode(filter)
                       + "&$orderby=" + System.Net.WebUtility.UrlEncode(orderby)
                       + "&$top=200";
      }

return-response.set-body:
@{
          var resp = (IResponse)context.Variables["dvResp"];
          var upn = (string)context.Variables["citizenUpn"];
          if (resp.StatusCode != 200) {
            string dvErr = "";
            try { dvErr = resp.Body.As(true); } catch { dvErr = ""; }
            return new JObject {
              ["value"] = new JArray(),
              ["count"] = 0,
              ["error"] = "dataverse_" + resp.StatusCode,
              ["citizenUpn"] = upn,
              ["dvBody"] = dvErr
            }.ToString();
          }
          JObject body;
          try { body = resp.Body.As(); }
          catch { return new JObject { ["value"] = new JArray(), ["count"] = 0, ["error"] = "dv_body_parse", ["citizenUpn"] = upn }.ToString(); }
          var rows = body["value"] as JArray;
          if (rows == null) { return new JObject { ["value"] = new JArray(), ["count"] = 0, ["error"] = "dv_value_null", ["citizenUpn"] = upn }.ToString(); }
          var items = new JArray();
          foreach (var row in rows) {
            string sub = (string)row["subject"] ?? "";
            string desc = (string)row["description"] ?? "";
            string text = desc;
            int idx = desc.IndexOf("| text:");
            if (idx > 0) { text = desc.Substring(idx + 7).Trim(); }
            items.Add(new JObject {
              ["id"] = (string)row["activityid"],
              ["activityid"] = (string)row["activityid"],
              ["caseId"] = (string)row["activityid"],
              ["title"] = sub,
              ["subject"] = sub,
              ["description"] = text,
              ["status"] = (int?)row["statuscode"] != null ? "statuscode " + row["statuscode"] : "Submitted",
              ["statecode"] = (int?)row["statecode"] ?? 0,
              ["createdOn"] = (string)row["createdon"],
              ["updatedAt"] = (string)row["modifiedon"] ?? (string)row["createdon"],
              ["country"] = sub.Length >= 8 ? sub.Substring(7, 2).ToLower() : null,
              ["applicationType"] = sub.Contains("residency") ? "residency-transfer"
                                  : sub.Contains("child") ? "child-benefit"
                                  : sub.Contains("tax") ? "tax-certificate" : "application"
            });
          }
          return new JObject { ["value"] = items, ["count"] = items.Count, ["citizenUpn"] = upn }.ToString();
      }

@{
          return new JObject {
            ["error"] = "lookup_failed",
            ["message"] = context.LastError != null ? context.LastError.Message : "unknown",
            ["correlationId"] = (string)context.Variables["correlationId"]
          }.ToString();
      }
